package main

import (
    "fmt"
    "io/ioutil"
    "net/http"
)

func webhookProxy(w http.ResponseWriter, r *http.Request) {
    url := r.URL.Query().Get("url") // Assuming the URL is passed as a query parameter
    
    resp, err := http.Get(url)
    if err != nil {
        fmt.Fprintf(w, "Error: %v", err)
        return
    }
    defer resp.Body.Close() // Close the response body when we're done
    
    body, err := ioutil.ReadAll(resp.Body) 
    if err != nil {
        fmt.Fprintf(w, "Error reading response: %v", err)
        return
    }

    w.Write(body) // Return the response to the client
}

func main() {
    http.HandleFunc("/proxy", webhookProxy) 
    
    fmt.Println("Listening on port 8080")
    err := http.ListenAndServe(":8080", nil) // Start the server
    if err != nil {
        panic(err)
    }
}